import * as React from "react";
import { graphql, Link } from "gatsby";
import { LayoutProse } from "src/components/layouts/layout";
import { SeoDefault } from "src/components/Seo";

const NotFoundPage = ({ data }) => {
  const pages = data.allMdx.nodes;

  const pTypeLabels = {
    pub: "Publications",
    projects: "Projects",
    models: "Models",
    blog: "Blog",
    news: "News",
    // papers: "Papers",
    // archive: "Archive",
  };

  const sortedpTypes = Object.keys(pTypeLabels).sort((a, b) =>
    pTypeLabels[a].localeCompare(pTypeLabels[b]),
  );

  const last5SortedpTypes = sortedpTypes.slice(-5);

  const filteredPages = pages.filter(
    (page) =>
      page.frontmatter.title && page.frontmatter.title !== "Placeholder",
  );

  const groupedPages = filteredPages.reduce((acc, page) => {
    const { p_type } = page.frontmatter;
    if (!acc[p_type]) {
      acc[p_type] = [];
    }
    if (acc[p_type].length < 5) {
      acc[p_type].push(page);
    }
    return acc;
  }, {});

  return (
    <LayoutProse pageTitle="Page not found">
      <main style={{ lineHeight: "2" }} className="sans-pretty">
        <>
          {/* Paragraph */}
          <p>
            Something's missing. This page is missing or you assembled the link
            incorrectly.{" "}
            <Link to="/" className="g-normal-link">
              Go back
            </Link>
          </p>

          {/* Suggestions */}
          <>
            <h2>Suggestions</h2>
            <ul
              style={{
                listStyleType: "disc",
                marginLeft: "2rem",
              }}
            >
              <li style={{ paddingLeft: "1rem" }}>Check your spelling</li>
              <li style={{ paddingLeft: "1rem" }}>
                Try a more general search query
              </li>
              <li style={{ paddingLeft: "1rem" }}>Try different keywords</li>
              <li style={{ paddingLeft: "1rem" }}>
                Browse{" "}
                <Link title="Home" to="/" className="g-normal-link">
                  all
                </Link>
              </li>
            </ul>
          </>

          {/* Recommended Pages last 5)*/}
          <>
            <h2 className="mt-16 md:mt-3">Latest pages</h2>

            <>
              {last5SortedpTypes.map((pType) => (
                <React.Fragment key={pType}>
                  <h3>
                    <Link className="g-hidden-link" to={`/${pType}`}>
                      {pTypeLabels[pType]}
                    </Link>
                  </h3>

                  <ul
                    style={{
                      listStyleType: "decimal",
                      marginLeft: "2rem",
                    }}
                  >
                    {groupedPages[pType].map((page) => (
                      <li
                        key={page.id}
                        style={{ paddingLeft: "1rem" }}
                        title={page.frontmatter.title}
                      >
                        <Link
                          title={page.frontmatter.title}
                          to={`/${pType}/${page.frontmatter.slug}`}
                        >
                          {page.frontmatter.title}
                        </Link>
                      </li>
                    ))}
                  </ul>

                  <div className="g-rml-wrp">
                    <Link to={`/${pType}/`}>Read more ...</Link>
                  </div>
                </React.Fragment>
              ))}
            </>
          </>
        </>
      </main>
    </LayoutProse>
  );
};

export default NotFoundPage;

export const Head = () => <SeoDefault title="404" />;

export const query = graphql`
  query NotFoundQuery {
    allMdx {
      nodes {
        id
        frontmatter {
          title
          slug
          p_type
        }
      }
    }
  }
`;
